function heading(kicker, title, copy, centered = true) {
  return `<div class="${centered ? "mx-auto max-w-3xl text-center" : "max-w-3xl"}"><div class="section-kicker mb-4">${kicker}</div><h2 class="section-title text-balance text-3xl font-extrabold tracking-tight text-slate-950 sm:text-4xl lg:text-5xl dark:text-white">${title}</h2><p class="section-copy mt-5 text-base sm:text-lg">${copy}</p></div>`;
}

function list(items) {
  return `<ul class="space-y-3 text-sm text-slate-600 dark:text-slate-300">${items.map((item) => `<li class="flex items-start gap-3"><span class="mt-0.5 inline-flex h-5 w-5 shrink-0 items-center justify-center rounded-full bg-emerald-500/15 text-emerald-500">${icon("check", "h-3.5 w-3.5")}</span><span>${item}</span></li>`).join("")}</ul>`;
}

function sectionWrap(inner, extra = "py-24") {
  return `<section class="${extra}"><div class="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">${inner}</div></section>`;
}

function buttons(base) {
  return `<div class="flex flex-col gap-3 sm:flex-row sm:items-center"><a href="${href(base, "pages/auth/register.html")}" class="btn-primary"><span>Get Started</span>${icon("arrow", "h-4 w-4")}</a><button type="button" data-modal-open="watch-demo" class="btn-secondary">${icon("play", "h-4 w-4")}<span>Watch Demo</span></button></div>`;
}

