function pageTemplate(page) {
  const base = toRoot(page.file);
  const title = `${page.name} | KA-Launchly`;
  const body = (() => {
    if (page.kind === "landing") return renderLanding(base, page);
    if (page.kind === "generic") return renderGenericPage(base, page);
    if (page.kind === "auth") return authShell(base, page);
    if (page.kind === "dashboard") return `${innerHero(page)}${dashboardContent()}${finalCta(base)}`;
    if (page.kind === "ui-kit") return `${innerHero(page)}${uiKitContent(base)}`;
    if (page.kind === "utility") return page.content(base);
    return "";
  })();
  return `<!DOCTYPE html><html lang="en" class="scroll-smooth"><head><meta charset="UTF-8" /><meta name="viewport" content="width=device-width, initial-scale=1.0" /><title>${title}</title><meta name="description" content="${page.description}" /><meta property="og:title" content="${title}" /><meta property="og:description" content="${page.description}" /><meta property="og:type" content="website" /><meta property="og:image" content="${href(base, "assets/img/og-cover.svg")}" /><meta name="theme-color" content="#0B1120" /><link rel="icon" type="image/svg+xml" href="${href(base, "assets/img/favicon.svg")}" /><link rel="preconnect" href="https://fonts.googleapis.com" /><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin /><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Plus+Jakarta+Sans:wght@400;500;600;700;800&display=swap" rel="stylesheet" />${page.needsSwiper ? '<link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/swiper@11/swiper-bundle.min.css" />' : ""}<script>(function(){const stored=window.localStorage.getItem("ka-theme");const useDark=stored?stored==="dark":window.matchMedia("(prefers-color-scheme: dark)").matches;document.documentElement.classList.toggle("dark",useDark);document.documentElement.dataset.theme=useDark?"dark":"light";})();</script><script src="https://cdn.tailwindcss.com?plugins=forms,typography"></script><script>tailwind.config={darkMode:"class"};</script><link rel="stylesheet" href="${href(base, "assets/css/styles.css")}" />${page.needsChart ? '<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.8/dist/chart.umd.min.js" defer></script>' : ""}${page.needsSwiper ? '<script src="https://cdn.jsdelivr.net/npm/swiper@11/swiper-bundle.min.js" defer></script>' : ""}<script src="${href(base, "assets/js/main.js")}" defer></script></head><body class="bg-transparent text-slate-900 antialiased dark:text-white">${page.minimal ? minimalHeader(base) : header(base, page.nav, page.announcement)}<main>${body}</main>${demoModal(base)}${page.minimal ? '<footer class="px-4 pb-8 text-center text-sm text-slate-500 dark:text-slate-400">&copy; <span data-current-year></span> KA-Launchly. Premium startup website template.</footer>' : footer(base)}</body></html>`;
}

