function buildReadme() {
  const groups = {
    Landing: ["index.html", "pages/saas-landing.html", "pages/startup-landing.html", "pages/ai-product-landing.html", "pages/mobile-app-landing.html"],
    Product: ["pages/features.html", "pages/product-overview.html", "pages/integrations.html", "pages/use-cases.html", "pages/roadmap.html", "pages/dashboard.html"],
    Pricing: ["pages/pricing.html", "pages/pricing-comparison.html", "pages/pricing-faq.html"],
    Blog: ["pages/blog/list.html", "pages/blog/grid.html", "pages/blog/article.html"],
    Docs: ["pages/docs/index.html", "pages/docs/getting-started.html", "pages/docs/api-documentation.html", "pages/docs/changelog.html"],
    Auth: ["pages/auth/login.html", "pages/auth/register.html", "pages/auth/forgot-password.html", "pages/auth/reset-password.html"],
    Company: ["pages/about.html", "pages/careers.html", "pages/contact.html", "pages/support.html"],
    Utility: ["pages/404.html", "pages/maintenance.html", "components/ui-kit.html"],
  };
  return `# KA-Launchly

KA-Launchly is a premium multi-page Startup & SaaS Website Template built with HTML5, TailwindCSS and Vanilla JavaScript.

## Highlights

- 30+ polished pages for startup, SaaS, AI and software product websites
- Dark and light mode support
- Sticky glassmorphism navbar and premium card system
- Reusable UI kit with buttons, pricing tables, tabs, dropdowns, accordion, modal and form patterns
- Blog, docs, auth, company and utility pages included
- Minimal JavaScript for reveal animations, theme toggle, tabs, accordion, dropdowns, modals and dashboard charts

## Tech Stack

- HTML5
- TailwindCSS via CDN
- Vanilla JavaScript
- Optional vendors loaded via CDN:
  - Chart.js
  - Swiper.js

## Build / Regenerate

\`\`\`bash
node scripts/build-site.mjs
\`\`\`

## File Structure

\`\`\`text
/assets
  /css
  /img
  /js
/components
/pages
  /auth
  /blog
  /docs
/scripts
index.html
README.md
\`\`\`

## Pages

${Object.entries(groups)
  .map(([group, files]) => `### ${group}\n\n${files
    .map((file) => {
      const page = pageDefinitions.find((entry) => entry.file === file);
      return `- \`${file}\` - ${page?.name || file}`;
    })
    .join("\n")}`)
  .join("\n\n")}

## Notes

- Replace logos, copy, metadata and contact details with your own brand data.
- TailwindCSS is loaded from CDN for easy editing. You can replace this with a local build later if desired.
- The dashboard demo is intentionally lightweight so the startup website remains the main focus.
`;
}

["assets", "assets/css", "assets/js", "assets/img", "pages", "pages/blog", "pages/docs", "pages/auth", "components"].forEach(ensureDir);
pageDefinitions.forEach((page) => writeFile(page.file, formatHtml(pageTemplate(page))));
writeFile("README.md", buildReadme());
console.log(`Generated ${pageDefinitions.length} pages and updated README.md`);
